LinK03:
23×28×33=21252，也就是MAX_DATE=21252，周期最多 21252 天一定会重复。
循环，利用x-p（第x天减去前置时间）能否整除周期来进行输出
源码：
#include<stdio.h>
#define MAX_DATE 21252
int main(void){

	int p,e,i,d;
	int caseCnt=1;
	int x;

	while(scanf("%d %d %d %d",&p,&e,&i,&d)==4){
		if(p==-1&&e==-1&&i==-1&&d==-1){
			break;
		}
		for(x=d+1;x<=d+MAX_DATE;x++){
			if((x-p)%23==0&&(x-e)%28==0&&(x-i)%33==0){
				break;
			}
		}
		printf("Case %d: the next triple peak occurs in %d days.\n",caseCnt++,x-d);
	}
	return 0;
}

